def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    result = []
    start = end = sorted_nums[0]

    for num in sorted_nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start != end:
                result.append(f'{start}-{end}')
            else:
                result.append(str(start))
            start = end = num

    if start != end:
        result.append(f'{start}-{end}')
    else:
        result.append(str(start))

    return ', '.join(result)
